-- =============================================================
--  TBG Moov Benin — Financial Data Warehouse
--  Source: TBG Moov_Africa_Bénin DEC 2025.xlsx
--  Generated automatically from Excel export
-- =============================================================

\set ON_ERROR_STOP on

-- -------------------------------------------------------------
--  Schema
-- -------------------------------------------------------------
CREATE SCHEMA IF NOT EXISTS tbg;
SET search_path = tbg, public;

-- -------------------------------------------------------------
--  1.  metric_definitions  (one row per sheet × metric)
-- -------------------------------------------------------------
CREATE TABLE IF NOT EXISTS metric_definitions (
    id            SERIAL       PRIMARY KEY,
    sheet         VARCHAR(60)  NOT NULL,
    metric_key    VARCHAR(120) NOT NULL,
    metric_code   VARCHAR(30),
    metric_label  TEXT         NOT NULL,
    UNIQUE (sheet, metric_key)
);

-- -------------------------------------------------------------
--  2.  tbg_data  (fact table — one row per sheet × metric × period)
-- -------------------------------------------------------------
CREATE TABLE IF NOT EXISTS tbg_data (
    id            BIGSERIAL    PRIMARY KEY,
    sheet         VARCHAR(60)  NOT NULL,
    metric_key    VARCHAR(120) NOT NULL,
    metric_label  TEXT         NOT NULL,
    period        DATE         NOT NULL,          -- always the 1st of the month
    reel          NUMERIC(22,4),
    budget        NUMERIC(22,4),
    ecart_budget  NUMERIC(22,4),
    n1_reel       NUMERIC(22,4),
    evol_pct      NUMERIC(12,6),
    UNIQUE (sheet, metric_key, period)
);

CREATE INDEX IF NOT EXISTS idx_tbg_data_sheet_period ON tbg_data (sheet, period);
CREATE INDEX IF NOT EXISTS idx_tbg_data_metric       ON tbg_data (metric_key);

-- =============================================================
--  metric_definitions  INSERTs
-- =============================================================
ON CONFLICT (sheet, metric_key) DO UPDATE
  SET metric_code = EXCLUDED.metric_code,
      metric_label = EXCLUDED.metric_label;

