-- =============================================================
--  Convenience views  (one per sheet)
-- =============================================================
CREATE OR REPLACE VIEW pnl_conso AS
  SELECT metric_key, metric_label, period,
         reel, budget, ecart_budget, n1_reel, evol_pct
  FROM   tbg_data
  WHERE  sheet = 'pnl_conso'
  ORDER BY metric_key, period;

