-- =============================================================
--  Useful analytical views
-- =============================================================
-- Latest period snapshot for every metric
CREATE OR REPLACE VIEW latest_snapshot AS
SELECT DISTINCT ON (sheet, metric_key)
       sheet, metric_key, metric_label, period,
       reel, budget, ecart_budget, n1_reel, evol_pct
FROM   tbg_data
ORDER  BY sheet, metric_key, period DESC;

-- YoY change summary for a quick overview
CREATE OR REPLACE VIEW yoy_summary AS
SELECT sheet,
       metric_key,
       metric_label,
       period,
       reel,
       n1_reel,
       CASE WHEN n1_reel <> 0
            THEN ROUND((reel - n1_reel) / ABS(n1_reel) * 100, 2)
       END AS yoy_pct,
       CASE WHEN budget <> 0
            THEN ROUND((reel - budget) / ABS(budget) * 100, 2)
       END AS vs_budget_pct
FROM   tbg_data
WHERE  reel IS NOT NULL;

-- Threshold breach helper — flag rows that exceed ±10 % YoY
CREATE OR REPLACE VIEW threshold_alerts AS
SELECT sheet,
       metric_key,
       metric_label,
       period,
       reel,
       n1_reel,
       ROUND((reel - n1_reel) / NULLIF(ABS(n1_reel), 0) * 100, 2) AS yoy_pct,
       CASE
         WHEN ABS((reel - n1_reel) / NULLIF(ABS(n1_reel), 0)) >= 0.20 THEN 'CRITICAL'
         WHEN ABS((reel - n1_reel) / NULLIF(ABS(n1_reel), 0)) >= 0.10 THEN 'WARNING'
         ELSE 'OK'
       END AS severity
FROM   tbg_data
WHERE  reel IS NOT NULL
  AND  n1_reel IS NOT NULL
  AND  n1_reel <> 0;
